regionCoords.tinaoRegion = [[[37.60081229967196, 55.576246101316656], [37.52193210259347, 55.59270138723204], [37.503936512059056, 55.59851266149937], [37.43021560262716, 55.66288510415413], [37.41648512325477, 55.68224126833525], [37.08396685813486, 55.587865251162754], [37.12335916209719, 55.44081687271583], [36.97160621279235, 55.45395298905126], [36.976821218228054, 55.50541825880029], [36.80796804606996, 55.50833561510052], [36.86285283333842, 55.401901872210544], [37.023111299743164, 55.28250496546474], [36.94746688152057, 55.24350721278856], [37.052205227743, 55.14556397784429], [37.15897707463256, 55.163040232696005], [37.159021729608014, 55.220730095095604], [37.27904837549394, 55.253314422582946], [37.38573787824106, 55.25112705796744], [37.46575226969901, 55.409345611179134], [37.38571543156817, 55.43962961346372], [37.435255798943814, 55.477441489067616], [37.543886934904634, 55.43204863999287], [37.60081229967196, 55.576246101316656]]];


document.addEventListener('DOMContentLoaded', () => {
    initMap();
});

async function initMap() {


    function getBounds(coords, paddingFactor = 0.1) {
        let minLat = Infinity;
        let minLng = Infinity;
        let maxLat = -Infinity;
        let maxLng = -Infinity;

        function walk(arr) {
            if (!Array.isArray(arr) || arr.length === 0) return;

            if (typeof arr[0] === 'number') {
                const [lng, lat] = arr;

                if (lat < minLat) minLat = lat;
                if (lat > maxLat) maxLat = lat;
                if (lng < minLng) minLng = lng;
                if (lng > maxLng) maxLng = lng;
            } else {
                arr.forEach(walk);
            }
        }

        walk(coords);


        const latDiff = maxLat - minLat;
        const lngDiff = maxLng - minLng;

        return [
            [minLng - lngDiff * paddingFactor, minLat - latDiff * paddingFactor],
            [maxLng + lngDiff * paddingFactor, maxLat + latDiff * paddingFactor]
        ];
    }

    await ymaps3.ready;

    const {
        YMap,
        YMapDefaultSchemeLayer,
        YMapDefaultFeaturesLayer,
        YMapFeature } = ymaps3;

    Array.from(document.querySelectorAll('.regions-map')).forEach(regionsMap => {
        const mapElement = regionsMap.querySelector('.regions-map__map');
        if (!mapElement) return;


        const initialBounds = getBounds([
            regionCoords.moscowRegion,
            regionCoords.zelenogradRegion,
            regionCoords.tinaoRegion
        ], 0.1);

        const initialLocation = {
            bounds: initialBounds
        };

        const map = new YMap(mapElement, {
            location: initialLocation,
            zoomRange: {
                min: 8,
                max: 20
            },
            // restrictMapArea: initialBounds,
            mode: 'vector'
        });

        const layer = new YMapDefaultSchemeLayer({
            customization: customization.light
        });

        const colorSchemeElement = regionsMap.closest('[data-color-scheme]') || document.querySelector('html');

        if (colorSchemeElement) {

            const colorScheme = colorSchemeElement.getAttribute('data-color-scheme');

            layer.update({
                customization: customization[colorScheme] || customization.light
            })

            map.update({
                theme: colorScheme
            })


        }

        const observer = new MutationObserver(([mutation]) => {
            const newValue = mutation.target.getAttribute('data-color-scheme');

            layer.update({
                customization: customization[newValue] || customization.light
            });

            map.update({
                theme: newValue
            });
        });

        observer.observe(colorSchemeElement, {
            attributes: true,
            attributeFilter: ['data-color-scheme'],
        });




        map.addChild(layer);
        map.addChild(new YMapDefaultFeaturesLayer());

        const regions = {};


        regions.moscowRegion = new YMapFeature({
            id: 'moscowRegion',
            properties: {
                title: 'Москва',
                clickTarget: 'regions-map-legend-button-moscow'
            },
            geometry: {
                type: 'Polygon',
                "coordinates": regionCoords.moscowRegion
            }
        });


        regions.zelenogradRegion = new YMapFeature({
            id: 'zelenogradRegion',
            properties: {
                title: 'Зеленоград',
                clickTarget: 'regions-map-legend-button-zelenograd'
            },
            geometry: {
                type: 'Polygon',
                "coordinates": regionCoords.zelenogradRegion
            }
        });


        regions.tinaoRegion = new YMapFeature({
            id: 'tinaoRegion',
            properties: {
                title: 'ТиНАО',
                clickTarget: 'regions-map-legend-button-tinao'
            },
            geometry: {
                type: 'Polygon',
                "coordinates": regionCoords.tinaoRegion
            }
        });


        map.addChild(regions.zelenogradRegion);
        map.addChild(regions.moscowRegion);
        map.addChild(regions.tinaoRegion);


        // ——————————————————————————————————————————————————

        const maximizeButton = regionsMap.querySelector('.regions-map__maximize');
        const closeButton = regionsMap.querySelector('.regions-map__close');
        const zoomInControl = regionsMap.querySelector('.regions-map__zoom-in');
        const zoomOutControl = regionsMap.querySelector('.regions-map__zoom-out');
        const legendTitle = regionsMap.querySelector('.regions-map__legend-title');
        const legendButton = regionsMap.querySelector('.regions-map__legend-button');





        mapElement.addEventListener('click', (e) => {
            const feature = e.target.closest?.('[data-feature-id]');
            const id = feature?.dataset?.featureId;

            const prev = regionsMap.querySelector('[data-feature-id][data-selected]');

            // клик по тому же региону (toggle off)
            if (prev && prev === feature) {
                prev.removeAttribute('data-selected');
                regionsMap.removeAttribute('data-region-selected');
                legendButton.removeAttribute('data-click-target');
                legendTitle.textContent = '';

                map.update({
                    location: {
                        ...initialLocation,
                        duration: 500
                    }
                });

                return;
            }

            // клик в пустоту
            if (!id) {
                if (prev) {
                    prev.removeAttribute('data-selected');
                    regionsMap.removeAttribute('data-region-selected');
                    legendButton.removeAttribute('data-click-target');
                    legendTitle.textContent = '';
                }

                map.update({
                    location: {
                        ...initialLocation,
                        duration: 500
                    }
                });

                return;
            }

            // сброс предыдущего выбора
            if (prev) {
                prev.removeAttribute('data-selected');
            }

            // установка нового состояния
            feature.setAttribute('data-selected', '');
            regionsMap.setAttribute('data-region-selected', id);
            legendButton.setAttribute('data-click-target', regions[id].properties.clickTarget);
            legendTitle.textContent = regions[id].properties.title;

            // bounds из исходных координат (не из feature)
            const bounds = getBounds(regionCoords[id], 0.08);

            map.update({
                location: {
                    bounds,
                    padding: [40, 200, 40, 40], // если есть боковая легенда
                    duration: 500,
                    easing: 'ease-in-out'
                }
            });
        });







        // ——————————————————————————————————————————————————



        if (zoomInControl) {
            zoomInControl.addEventListener('click', () => {
                map.update({
                    location: {
                        zoom: map.zoom + 1,
                        duration: 500,
                    }
                })
            });
        }

        if (zoomOutControl) {
            zoomOutControl.addEventListener('click', () => {
                map.update({
                    location: {
                        zoom: map.zoom - 1,
                        duration: 500,
                    }
                })
            });
        }







        const close = () => {
            if (regionsMap.hasAttribute('data-fullscreen-only')) {
                regionsMap.close();
            } else {
                regionsMap.close();
                regionsMap.show();
            }
        }

        if (maximizeButton) {
            maximizeButton.addEventListener('click', () => {
                regionsMap.close();
                regionsMap.showModal();
            })
        }

        if (closeButton) {
            closeButton.addEventListener('click', () => {
                close();
            })
        }

        if (legendButton) {
            legendButton.addEventListener('click', () => {
                if (!regionsMap.hasAttribute('data-fullscreen-only')) return;
                close();
            })
        }

    })

    Array.from(document.querySelectorAll("[data-regions-map]")).forEach(button => {
        const regionsMap = document.querySelector(`#${button.getAttribute('data-regions-map')}`);
        if (!regionsMap) return;

        button.addEventListener('click', () => {
            regionsMap.close();
            regionsMap.showModal();
        })
    })
}



